THOUGHT: The crash arises because SLP inserts an insertelement using a scalar like a function argument (%arg) at a position that does not dominate all its uses across blocks. To ensure dominance, I will adjust the gather’s CreateInsertElement lambda to insert such scalar-based insertelements at a safe location: the beginning of the function entry block (after PHIs). I will temporarily change the IRBuilder’s insertion point when the scalar does not dominate the current insertion point, create the insertelement, and then restore the original insertion point.

```bash
python3 - << 'PY'
import re
path = "llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp"
with open(path, 'r') as f:
    s = f.read()
# Find the CreateInsertElement lambda and inject dominance-safe insertion point handling.
pattern = r'(auto &&CreateInsertElement = \[this\]\(Value \*Vec, Value \*V, unsigned Pos,
\s*Type \*Ty\) \{
\s*Value \*Scalar = V;
)'
inject = r"""\1    // Ensure insertelement is created at a position dominating all uses.
    // If the scalar does not dominate the current insertion point (e.g., function
    // arguments/constants across blocks), insert at the beginning of the entry block.
    llvm::BasicBlock *SavedBB = Builder.GetInsertBlock();
    auto SavedIt = Builder.GetInsertPoint();
    llvm::Instruction *CurIP = SavedIt != SavedBB->end() ? &*SavedIt : SavedBB->getTerminator();
    bool NeedSafeIP = true;
    if (auto *InstScalar = llvm::dyn_cast<llvm::Instruction>(Scalar)) {
      // If the scalar instruction dominates the current insertion point, we can use it.
      if (DT && CurIP && DT->dominates(InstScalar, CurIP))
        NeedSafeIP = false;
    } else {
      // For non-instruction scalars (e.g., arguments/constants), keep NeedSafeIP true.
    }
    if (NeedSafeIP) {
      llvm::Function *F = SavedBB->getParent();
      llvm::BasicBlock &Entry = F->getEntryBlock();
      auto FirstNonPHI = Entry.getFirstNonPHIIt();
      if (FirstNonPHI != Entry.end() && Entry.isLandingPad())
        ++FirstNonPHI;
      Builder.SetInsertPoint(&Entry, FirstNonPHI);
    }
"""
s_new = re.sub(pattern, inject, s, count=1)
# After creating the insertelement (both vector_insert and insertelement cases), restore insertion point.
restore_pattern = r'(\s*GatherShuffleExtractSeq\.insert\(InsElt\);
\s*CSEBlocks\.insert\(InsElt->getParent\(\)\);
)'
restore_inject = r"""\1    // Restore original insertion point after creating insertelement.
    if (SavedBB)
      Builder.SetInsertPoint(SavedBB, SavedIt);
"""
s_new = re.sub(restore_pattern, restore_inject, s_new, count=1)
with open(path, 'w') as f:
    f.write(s_new)
print("Patched dominance-safe insertelement creation.")
PY
