import re
p = "llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp"
s = open(p).read()
start = s.find("void BoUpSLP::setInsertPointAfterBundle(const TreeEntry *E) {")
end = s.find("}\n", start) + 2
block = s[start:end]
# Replace insertion logic to always insert at entry block first non-PHI.
new_block = re.sub(r'Builder\.SetInsertPoint\([^\)]*\);\n', '', block)
ins = r'''
  // Conservatively insert at the beginning of the entry block (after PHIs)
  // to ensure dominance of created instructions across complex CFGs.
  llvm::Function *F = LastInst->getFunction();
  llvm::BasicBlock &Entry = F->getEntryBlock();
  auto FirstNonPHI = Entry.getFirstNonPHIIt();
  if (FirstNonPHI != Entry.end() && Entry.isLandingPad())
    ++FirstNonPHI;
  Builder.SetInsertPoint(&Entry, FirstNonPHI);
  Builder.SetCurrentDebugLocation(Front->getDebugLoc());
}
'''
new_block = re.sub(r'\s*Builder\.SetCurrentDebugLocation\(Front->getDebugLoc\(\)\);\s*\n\s*\}', ins, new_block)
